    (function () {
      const canvas = document.getElementById("game");
      const ctx = canvas.getContext("2d");
      const timeEl = document.getElementById("time");
      const statusEl = document.getElementById("status");

      const keys = Object.create(null);
      const level = {
        start: { x: 60, y: 60 },
        goal: { x: 730, y: 430, w: 60, h: 60 },
        walls: [
          { x: 120, y: 0, w: 22, h: 360 },
          { x: 250, y: 160, w: 22, h: 360 },
          { x: 380, y: 0, w: 22, h: 330 },
          { x: 520, y: 190, w: 22, h: 330 },
          { x: 650, y: 0, w: 22, h: 350 },
          { x: 120, y: 338, w: 152, h: 22 },
          { x: 250, y: 160, w: 152, h: 22 },
          { x: 380, y: 308, w: 162, h: 22 },
          { x: 520, y: 190, w: 152, h: 22 },
          { x: 650, y: 348, w: 110, h: 22 }
        ],
        hazards: [
          { x: 155, y: 390, w: 70, h: 70 },
          { x: 420, y: 95, w: 70, h: 70 },
          { x: 565, y: 390, w: 70, h: 70 }
        ]
      };

      const marble = {
        x: level.start.x,
        y: level.start.y,
        radius: 14,
        vx: 0,
        vy: 0
      };

      const settings = {
        accel: 900,
        friction: 0.985,
        maxSpeed: 320,
        bounce: 0.25,
        timeLimit: 45
      };

      let timeRemaining = settings.timeLimit;
      let state = "playing";
      let lastTimestamp = 0;

      function resetGame() {
        marble.x = level.start.x;
        marble.y = level.start.y;
        marble.vx = 0;
        marble.vy = 0;
        timeRemaining = settings.timeLimit;
        state = "playing";
        statusEl.textContent = "Reach the green goal and avoid the red hazards.";
        timeEl.textContent = timeRemaining.toFixed(1);
      }

      function circleIntersectsRect(cx, cy, r, rect) {
        const nearestX = Math.max(rect.x, Math.min(cx, rect.x + rect.w));
        const nearestY = Math.max(rect.y, Math.min(cy, rect.y + rect.h));
        const dx = cx - nearestX;
        const dy = cy - nearestY;
        return dx * dx + dy * dy <= r * r;
      }

      function resolveWallCollisions(prevX, prevY) {
        for (const wall of level.walls) {
          if (!circleIntersectsRect(marble.x, marble.y, marble.radius, wall)) {
            continue;
          }

          const collidedAfterXMove = circleIntersectsRect(marble.x, prevY, marble.radius, wall);
          const collidedAfterYMove = circleIntersectsRect(prevX, marble.y, marble.radius, wall);

          if (collidedAfterXMove && !collidedAfterYMove) {
            marble.x = prevX;
            marble.vx *= -settings.bounce;
          } else if (!collidedAfterXMove && collidedAfterYMove) {
            marble.y = prevY;
            marble.vy *= -settings.bounce;
          } else {
            marble.x = prevX;
            marble.y = prevY;
            marble.vx *= -settings.bounce;
            marble.vy *= -settings.bounce;
          }
        }
      }

      function update(dt) {
        if (state !== "playing") {
          return;
        }

        timeRemaining = Math.max(0, timeRemaining - dt);
        timeEl.textContent = timeRemaining.toFixed(1);

        if (timeRemaining <= 0) {
          state = "lost";
          statusEl.textContent = "Time up! Press R to restart.";
          return;
        }

        let ax = 0;
        let ay = 0;

        if (keys.ArrowLeft || keys.a || keys.A) ax -= settings.accel;
        if (keys.ArrowRight || keys.d || keys.D) ax += settings.accel;
        if (keys.ArrowUp || keys.w || keys.W) ay -= settings.accel;
        if (keys.ArrowDown || keys.s || keys.S) ay += settings.accel;

        marble.vx += ax * dt;
        marble.vy += ay * dt;

        marble.vx *= settings.friction;
        marble.vy *= settings.friction;

        const speed = Math.hypot(marble.vx, marble.vy);
        if (speed > settings.maxSpeed) {
          const scale = settings.maxSpeed / speed;
          marble.vx *= scale;
          marble.vy *= scale;
        }

        const prevX = marble.x;
        const prevY = marble.y;

        marble.x += marble.vx * dt;
        marble.y += marble.vy * dt;

        if (marble.x - marble.radius < 0) {
          marble.x = marble.radius;
          marble.vx *= -settings.bounce;
        } else if (marble.x + marble.radius > canvas.width) {
          marble.x = canvas.width - marble.radius;
          marble.vx *= -settings.bounce;
        }

        if (marble.y - marble.radius < 0) {
          marble.y = marble.radius;
          marble.vy *= -settings.bounce;
        } else if (marble.y + marble.radius > canvas.height) {
          marble.y = canvas.height - marble.radius;
          marble.vy *= -settings.bounce;
        }

        resolveWallCollisions(prevX, prevY);

        for (const hazard of level.hazards) {
          if (circleIntersectsRect(marble.x, marble.y, marble.radius, hazard)) {
            state = "lost";
            statusEl.textContent = "You hit a hazard! Press R to restart.";
            return;
          }
        }

        if (circleIntersectsRect(marble.x, marble.y, marble.radius, level.goal)) {
          state = "won";
          statusEl.textContent = "You escaped the maze! Press R to play again.";
        }
      }

      function drawRect(rect, fill, stroke) {
        ctx.fillStyle = fill;
        ctx.fillRect(rect.x, rect.y, rect.w, rect.h);
        if (stroke) {
          ctx.strokeStyle = stroke;
          ctx.lineWidth = 2;
          ctx.strokeRect(rect.x, rect.y, rect.w, rect.h);
        }
      }

      function render() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        const bg = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
        bg.addColorStop(0, "#0c1631");
        bg.addColorStop(1, "#08101e");
        ctx.fillStyle = bg;
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        drawRect(level.goal, "#1d8f52", "#8af0b1");

        for (const hazard of level.hazards) {
          drawRect(hazard, "#9c1c30", "#ff7a92");
        }

        for (const wall of level.walls) {
          drawRect(wall, "#6074c9", "#b8c4ff");
        }

        drawRect({ x: 20, y: 20, w: 56, h: 56 }, "#1d3f84", "#8fb3ff");
        ctx.fillStyle = "#d9e4ff";
        ctx.font = "12px monospace";
        ctx.fillText("START", 27, 52);

        const marbleGradient = ctx.createRadialGradient(
          marble.x - 5,
          marble.y - 5,
          4,
          marble.x,
          marble.y,
          marble.radius
        );
        marbleGradient.addColorStop(0, "#ffffff");
        marbleGradient.addColorStop(0.4, "#b9c7ff");
        marbleGradient.addColorStop(1, "#4c66d6");
        ctx.fillStyle = marbleGradient;
        ctx.beginPath();
        ctx.arc(marble.x, marble.y, marble.radius, 0, Math.PI * 2);
        ctx.fill();
        ctx.strokeStyle = "#eef2ff";
        ctx.lineWidth = 2;
        ctx.stroke();

        if (state !== "playing") {
          ctx.fillStyle = "rgba(0, 0, 0, 0.45)";
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.fillStyle = "#f4f6ff";
          ctx.textAlign = "center";
          ctx.font = "bold 30px monospace";
          ctx.fillText(state === "won" ? "YOU WIN" : "GAME OVER", canvas.width / 2, canvas.height / 2 - 10);
          ctx.font = "18px monospace";
          ctx.fillText("Press R to restart", canvas.width / 2, canvas.height / 2 + 28);
          ctx.textAlign = "start";
        }
      }

      function frame(timestamp) {
        if (!lastTimestamp) {
          lastTimestamp = timestamp;
        }
        const dt = Math.min((timestamp - lastTimestamp) / 1000, 0.033);
        lastTimestamp = timestamp;
        update(dt);
        render();
        requestAnimationFrame(frame);
      }

      window.addEventListener("keydown", function (event) {
        keys[event.key] = true;
        if (event.key === "r" || event.key === "R") {
          resetGame();
        }
      });

      window.addEventListener("keyup", function (event) {
        keys[event.key] = false;
      });

      resetGame();
      requestAnimationFrame(frame);
    })();
  </script>
